140	func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
141		normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
142		if err != nil {
143			return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
144		}
145		if normalizedCommitSHA == "" {
146			return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
147		}
148		return normalizedCommitSHA, nil
149	}
