673	func (f *CommandFactory) newBeadCloseCommand() *cobra.Command {
674		cmd := &cobra.Command{
675			Use:   "close <id>",
676			Short: "Close a bead",
677			Args:  cobra.ExactArgs(1),
678			RunE: func(cmd *cobra.Command, args []string) error {
679				s := f.beadStore()
680				sessionID, _ := cmd.Flags().GetString("session")
681				commitSHA, _ := cmd.Flags().GetString("commit")
682	
683				if commitSHA != "" {
684					normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
685					if err != nil {
686						return err
687					}
688					commitSHA = normalizedCommitSHA
689				}
690	
691				target, err := s.Get(args[0])
692				if err != nil {
693					return err
694				}
695				// CloseWithEvidence runs the closure gate (ddx-e30e60a9); manual
696				// operator closes without evidence are intentionally a separate
697				// path. When --session and --commit are both unset, we are in
698				// manual-administration territory ŌĆö use the ungated Store.Close
699				// so the gate doesn't reject legitimate tracker admin.
700				if sessionID == "" && commitSHA == "" {
701					if err := s.Close(args[0]); err != nil {
702						return err
703					}
704				} else if err := s.CloseWithEvidence(args[0], sessionID, commitSHA); err != nil {
705					return err
706				}
707	
708				landedSHA := f.beadAutoCommit("close " + args[0])
709				if commitSHA == "" && landedSHA != "" {
710					if f.commitIsMetadataOnlyTrackerBackfill(landedSHA) {
711						if isReviewCloseBead(target) {
712							// Tracker-only review-finding closes must not retain any prior
713							// replay boundary. The close commit itself is the metadata-only
714							// backfill, so clear stale closing provenance instead of
715							// preserving an unrelated implementation SHA.
716							if err := s.Update(args[0], func(b *bead.Bead) {
717								if b.Extra == nil {
718									return
719								}
720								delete(b.Extra, "closing_commit_sha")
721							}); err != nil {
722								return err
723							}
724							if followupSHA := f.beadAutoCommit("close " + args[0]); followupSHA == "" {
725								return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
726							}
727						}
728					} else {
729						// Only stamp closing provenance when the close commit includes
730						// real implementation work. Pure tracker backfills should not
731						// advertise a replay boundary that points at metadata-only
732						// provenance.
733						if err := s.Update(args[0], func(b *bead.Bead) {
734							if b.Extra == nil {
735								b.Extra = make(map[string]any)
736							}
737							b.Extra["closing_commit_sha"] = landedSHA
738						}); err != nil {
739							return err
740						}
741						if followupSHA := f.beadAutoCommit("close " + args[0]); followupSHA == "" {
742							return fmt.Errorf("close %s: failed to auto-commit closing provenance", args[0])
743						}
744					}
745				}
746				return nil
747			},
748		}
749		cmd.Flags().String("session", "", "Agent session ID that completed this bead")
750		cmd.Flags().String("commit", "", "Closing commit SHA (auto-detected if not provided)")
751		return cmd
752	}
